function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const yToXs = new Map<number, number[]>();

    for (const [x, y] of points) {
        if (!yToXs.has(y)) {
            yToXs.set(y, []);
        }
        yToXs.get(y)!.push(x);
    }

    // Sort the x coordinates for each y
    for (const y of yToXs.keys()) {
        yToXs.get(y)!.sort((a, b) => a - b);
    }

    // Get ys with at least 2 points and sort them
    const ys = Array.from(yToXs.keys())
        .filter(y => yToXs.get(y)!.length >= 2)
        .sort((a, b) => a - b);

    let res = 0;

    for (let i = 0; i < ys.length; i++) {
        const y1 = ys[i];
        const xs1 = yToXs.get(y1)!;
        const m = xs1.length;

        for (let j = i + 1; j < ys.length; j++) {
            const y2 = ys[j];
            const xs2 = yToXs.get(y2)!;
            const n = xs2.length;

            if (m >= 2 && n >= 2) {
                const cnt = (m * (m - 1) / 2) * (n * (n - 1) / 2);
                res = (res + cnt) % MOD;
            }
        }
    }

    return res;
}
